    public String getXPath() {
        StringBuilder r = new StringBuilder();
        if (parent != null) {
            XNElement q = this;
            XNElement p = parent;
            while (p != null) {
                if (p.children.size() > 1) {
                    int count = 0;
                    int idx = 0;
                    for (XNElement c : p.children) {
                        if (q.name.equals(c.name) && Objects.equals(q.namespace, c.namespace)) {
                            if (c == q) {
                                idx = count;
                                break;
                            }
                            count++;
                        }
                    }
                    if (idx > 0) {
                        r.insert(0, ']');
                        r.insert(0, idx);
                        r.insert(0, '[');
                        r.insert(0, p.name);
                        r.insert(0, '/');
                    } else {
                        r.insert(0, p.name);
                        r.insert(0, '/');
                    }
                } else {
                    r.insert(0, p.name);
                    r.insert(0, '/');
                }

                q = p;
                p = p.parent;
            }
        }
        r.append('/').append(name);
        return r.toString();
    }

